namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
    public int RatingCount => Ratings.Count;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
                Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
                Ratings = [5, 4, 5, 4, 5]
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = "Spaghetti\nGuanciale or pancetta\nEgg yolks\nPecorino Romano\nBlack pepper",
                Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan.\n3. Whisk egg yolks with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, stir in egg mixture quickly.\n6. Serve immediately with extra cheese.",
                Ratings = [5, 5, 4]
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger\nOnion",
                Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 minutes.\n5. Add cream and grilled chicken.\n6. Simmer 10 more minutes. Serve with rice or naan.",
                Ratings = [5, 4, 4, 5]
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
                Ingredients = "Rice noodles\nTofu\nBean sprouts\nGreen onions\nPeanuts\nLime\nTamarind paste\nFish sauce\nSugar\nEgg",
                Steps = "1. Soak rice noodles in warm water for 30 minutes.\n2. Mix tamarind paste, fish sauce, and sugar for sauce.\n3. Press and cube tofu, pan-fry until golden.\n4. Scramble egg in the same pan.\n5. Add drained noodles and sauce, toss to coat.\n6. Top with bean sprouts, peanuts, green onions, and lime.",
                Ratings = [4, 4, 3, 5]
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
                Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer until thickened.\n3. Warm tortillas in a dry pan.\n4. Fill tortillas with seasoned beef.\n5. Top with lettuce, tomato, cheese, sour cream, and salsa.",
                Ratings = [4, 5, 4]
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt\nGarlic",
                Steps = "1. Halve and pit avocados, scoop into a bowl.\n2. Mash to desired consistency.\n3. Stir in diced onion, tomato, jalapeño, and cilantro.\n4. Add lime juice, garlic, and salt to taste.\n5. Serve immediately with tortilla chips.",
                Ratings = [5, 5, 5, 4, 5]
            },
            new Recipe
            {
                Id = 7, Title = "Miso Soup", Category = "Japanese",
                Ingredients = "Dashi stock\nWhite miso paste\nSilken tofu\nWakame seaweed\nGreen onions",
                Steps = "1. Heat dashi stock in a pot.\n2. Rehydrate wakame in water, drain.\n3. Cube silken tofu.\n4. Dissolve miso paste in a ladle of warm dashi.\n5. Add tofu and wakame to the pot.\n6. Stir in miso mixture. Do not boil.\n7. Garnish with sliced green onions.",
                Ratings = [4, 3, 4]
            },
            new Recipe
            {
                Id = 8, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Ingredients = "Butter\nSugar\nBrown sugar\nEggs\nVanilla extract\nFlour\nBaking soda\nSalt\nChocolate chips",
                Steps = "1. Preheat oven to 375°F.\n2. Cream butter with sugars until fluffy.\n3. Beat in eggs and vanilla.\n4. Mix flour, baking soda, and salt; add to wet ingredients.\n5. Fold in chocolate chips.\n6. Drop spoonfuls onto baking sheets.\n7. Bake 9-11 minutes until golden edges.",
                Ratings = [5, 5, 4, 5, 5]
            },
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

