@page "/category/{CategoryName}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row mt-3">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted mb-1">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>@RenderStars(recipe.AverageRating) (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary mt-2">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe Not Found")</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="/" class="btn btn-primary">Back to Home</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <div class="mb-4">
        <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">🥕 Ingredients</h5></div>
                <div class="card-body">
                    <ul class="list-unstyled mb-0">
                        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <li class="mb-1">• @ingredient</li>
                        }
                    </ul>
                </div>
            </div>
        </div>

        <div class="col-md-8">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">📝 Steps</h5></div>
                <div class="card-body">
                    @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p class="mb-2">@step</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@Title</strong>" has been added.</p>
        <a href="recipe/@NewRecipeId" class="btn btn-primary">View Your Recipe</a>
    </div>
}
else
{
    <EditForm FormName="submit-recipe" Model="this" OnValidSubmit="HandleSubmit" class="mt-3">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="Ingredients" class="form-control" rows="6"
                placeholder="One ingredient per line" />
            <ValidationMessage For="() => Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="Steps" class="form-control" rows="6"
                placeholder="1. First step&#10;2. Second step&#10;3. Third step" />
            <ValidationMessage For="() => Steps" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsFormValid)">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private string Title { get; set; } = string.Empty;
    private string Category { get; set; } = string.Empty;
    private string Ingredients { get; set; } = string.Empty;
    private string Steps { get; set; } = string.Empty;
    private bool Submitted { get; set; }
    private int NewRecipeId { get; set; }

    private bool IsFormValid =>
        !string.IsNullOrWhiteSpace(Title) &&
        !string.IsNullOrWhiteSpace(Category) &&
        !string.IsNullOrWhiteSpace(Ingredients) &&
        !string.IsNullOrWhiteSpace(Steps);

    private void HandleSubmit()
    {
        if (!IsFormValid) return;

        var recipe = RecipeService.AddRecipe(Title, Category, Ingredients, Steps);
        NewRecipeId = recipe.Id;
        Submitted = true;
    }
}

@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (HoverStar ?? SelectedStar) ? "filled" : "")"
              @onclick="() => Rate(star)"
              @onmouseover="() => HoverStar = star"
              @onmouseout="() => HoverStar = null"
              role="button"
              title="Rate @star star(s)">
            ★
        </span>
    }

    @if (RatingSubmitted)
    {
        <span class="text-success ms-2">✓ Thanks!</span>
    }

    @{ var recipe = RecipeService.GetById(RecipeId); }
    @if (recipe is not null && recipe.RatingCount > 0)
    {
        <span class="text-muted ms-2">
            @recipe.AverageRating.ToString("F1") avg (@recipe.RatingCount ratings)
        </span>
    }
</div>

@code {
    [Parameter, EditorRequired] public int RecipeId { get; set; }

    private int SelectedStar { get; set; }
    private int? HoverStar { get; set; }
    private bool RatingSubmitted { get; set; }

    private void Rate(int stars)
    {
        SelectedStar = stars;
        RecipeService.AddRating(RecipeId, stars);
        RatingSubmitted = true;
    }
}

.star-rating .star {
    font-size: 1.8rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.15s;
    user-select: none;
}

.star-rating .star.filled {
    color: #ffc107;
}

.star-rating .star:hover {
    transform: scale(1.2);
}

