@page "/"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<h1>🍳 Recipe Community</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2 class="mt-4">Browse by Category</h2>
<div class="row mt-3">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 col-sm-6 mb-4">
            <div class="card h-100 shadow-sm">
                <div class="card-body text-center">
                    <h3 class="card-title">
                        <span class="category-emoji">@GetEmoji(category)</span>
                    </h3>
                    <h4>@category</h4>
                    <p class="text-muted">@RecipeService.GetByCategory(category).Count recipe(s)</p>
                    <a href="category/@category" class="btn btn-outline-primary">Browse Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static string GetEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🥘",
        "Mexican" => "🌮",
        "Japanese" => "🍣",
        "Desserts" => "🍪",
        _ => "🍽️"
    };
}

