+              @onmouseover="() => HoverStar = star"
+              @onmouseout="() => HoverStar = null"
+              role="button"
+              title="Rate @star star(s)">
+            ★
+        </span>
+    }
+
+    @if (RatingSubmitted)
+    {
+        <span class="text-success ms-2">✓ Thanks!</span>
+    }
+
+    @{ var recipe = RecipeService.GetById(RecipeId); }
+    @if (recipe is not null && recipe.RatingCount > 0)
+    {
+        <span class="text-muted ms-2">
+            @recipe.AverageRating.ToString("F1") avg (@recipe.RatingCount ratings)
+        </span>
+    }
+</div>
+
+@code {
+    [Parameter, EditorRequired] public int RecipeId { get; set; }
+
+    private int SelectedStar { get; set; }
+    private int? HoverStar { get; set; }
+    private bool RatingSubmitted { get; set; }
+
+    private void Rate(int stars)
+    {
+        SelectedStar = stars;
+        RecipeService.AddRating(RecipeId, stars);
+        RatingSubmitted = true;
+    }
+}
+

